      "content": "const { randomUUID } = require('node:crypto');
const projectsService = require('../projects/service');
const errors = require('../../lib/errors');

function addMemberToProject(projectId, userId, role) {
  const project = projectsService.getProjectById(projectId);
  if (!project) return null;
  if (project.members.some(member => member.userId === userId)) return null;
  const memberId = randomUUID();
  project.members.push({ id: memberId, userId, role });
  return { id: memberId, userId, role };
}

module.exports = {
  addMemberToProject
};
